import { Link, useLocation } from "react-router-dom";
import { useAuth } from "../App";

const nav = [
  { path: "/dashboard", label: "Dashboard",  icon: "âšˇ" },
  { path: "/alerts",    label: "Alerts",     icon: "đź””" },
  { path: "/settings",  label: "Settings",   icon: "âš™ď¸Ź" },
];

export default function Sidebar() {
  const { pathname } = useLocation();
  const { user, logout } = useAuth();

  return (
    <aside style={styles.sidebar}>
      <div style={styles.logo}>
        <span style={styles.logoIcon}>âšˇ</span>
        <div>
          <div style={styles.logoTitle}>IEMS</div>
          <div style={styles.logoSub}>Energy Management</div>
        </div>
      </div>

      <nav style={styles.nav}>
        {nav.map(({ path, label, icon }) => (
          <Link key={path} to={path} style={{
            ...styles.link,
            ...(pathname === path ? styles.active : {})
          }}>
            <span>{icon}</span>
            <span>{label}</span>
          </Link>
        ))}
      </nav>

      <div style={styles.footer}>
        <div style={styles.userInfo}>
          <div style={styles.avatar}>{user?.name?.[0] ?? "U"}</div>
          <div>
            <div style={styles.userName}>{user?.name}</div>
            <div style={styles.userRole}>{user?.role?.replace("_", " ")}</div>
          </div>
        </div>
        <button onClick={logout} style={styles.logout}>Logout</button>
      </div>
    </aside>
  );
}

const styles = {
  sidebar: {
    width: 240,
    minHeight: "100vh",
    background: "#0f172a",
    display: "flex",
    flexDirection: "column",
    padding: "24px 0",
    boxShadow: "2px 0 12px rgba(0,0,0,0.3)",
  },
  logo: {
    display: "flex",
    alignItems: "center",
    gap: 12,
    padding: "0 24px 32px",
    borderBottom: "1px solid #1e293b",
  },
  logoIcon:  { fontSize: 28 },
  logoTitle: { color: "#38bdf8", fontWeight: 700, fontSize: 18 },
  logoSub:   { color: "#64748b", fontSize: 11 },
  nav: { flex: 1, padding: "24px 12px", display: "flex", flexDirection: "column", gap: 4 },
  link: {
    display: "flex", alignItems: "center", gap: 12,
    padding: "10px 12px", borderRadius: 8,
    color: "#94a3b8", textDecoration: "none",
    fontSize: 14, fontWeight: 500, transition: "all 0.2s",
  },
  active: { background: "#1e3a5f", color: "#38bdf8" },
  footer: { padding: "16px 24px", borderTop: "1px solid #1e293b" },
  userInfo: { display: "flex", alignItems: "center", gap: 10, marginBottom: 12 },
  avatar: {
    width: 36, height: 36, borderRadius: "50%",
    background: "#38bdf8", color: "#0f172a",
    display: "flex", alignItems: "center", justifyContent: "center",
    fontWeight: 700, fontSize: 14,
  },
  userName: { color: "#e2e8f0", fontSize: 13, fontWeight: 600 },
  userRole: { color: "#64748b", fontSize: 11, textTransform: "capitalize" },
  logout: {
    width: "100%", padding: "8px", background: "#1e293b",
    color: "#f87171", border: "none", borderRadius: 6,
    cursor: "pointer", fontSize: 13, fontWeight: 500,
  },
};
